  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 0, 'II Thessalonians 1:1', 'DAILY BREAD', '2thessalonians', 'II Thessalonians', 1, ARRAY[1], 'Paul and Sylvanus and Timothy, to the church of the Thessalonians, in God our Father and the Lord Jesus Christ.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 1, 'Numbers 25:9', 'DAILY BREAD', 'numbers', 'Numbers', 25, ARRAY[9], 'And there were slain twenty-four thousand men.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 2, 'Numbers 5:5', 'DAILY BREAD', 'numbers', 'Numbers', 5, ARRAY[5], 'And the Lord spoke to Moses, saying:') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 3, 'Zechariah 6:12', 'DAILY BREAD', 'zechariah', 'Zechariah', 6, ARRAY[12], 'And you will speak to him, saying: Thus says the Lord of hosts, saying: Behold, a man; the Rising is his name. And under him, he will rise up, and he will build a temple to the Lord.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 4, 'Micah 4:13', 'DAILY BREAD', 'micah', 'Micah', 4, ARRAY[13], 'Rise and thresh, daughter of Zion. For I will set your horn like iron, and I will set your hoofs like brass. And you will shatter many peoples, and you will immolate their spoils for the Lord, and their strength for the Lord of the whole earth.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 5, 'Isaiah 2:22', 'DAILY BREAD', 'isaiah', 'Isaiah', 2, ARRAY[22], 'Therefore, rest away from man, whose breath is in his nostrils, for he considers himself to be exalted.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 6, 'II Chronicles 28:15', 'DAILY BREAD', '2chronicles', 'II Chronicles', 28, ARRAY[15], 'And the men, whom we mentioned above, rose up and took the captives. All those who were naked, they clothed from the spoils. And when they had clothed them, and had given them shoes, and had refreshed them with food and drink, and had anointed them because of the hardship, and had cared for them, whoever was not able to walk and whoever was feeble in body, they set them upon beasts of burden, and they led them to Jericho, the city of palm trees, to their brothers, and they themselves returned to Samaria.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 7, 'Genesis 40:21', 'DAILY BREAD', 'genesis', 'Genesis', 40, ARRAY[21], 'And he restored the one to his place, to present him the cup;') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 8, 'I Kings 21:23', 'DAILY BREAD', '1kings', 'I Kings', 21, ARRAY[23], 'And about Jezebel also, the Lord spoke, saying: ‘The dogs shall consume Jezebel in the field of Jezreel.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 9, 'Habakkuk 1:6', 'DAILY BREAD', 'habakkuk', 'Habakkuk', 1, ARRAY[6], 'For behold, I will raise up the Chaldeans, a bitter and swift people, marching across the width of the earth, to possess tabernacles not their own.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 10, 'Lamentations 2:9', 'DAILY BREAD', 'lamentations', 'Lamentations', 2, ARRAY[9], 'TETH. Her gates have been buried in the ground. He has ruined and crushed its bars. Her king and her princes are with the Gentiles. There is no law, and her prophets have found no vision from the Lord.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 11, 'I Chronicles 2:33', 'DAILY BREAD', '1chronicles', 'I Chronicles', 2, ARRAY[33], 'And Jonathan conceived Peleth and Zaza. These were the sons of Jerahmeel.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 12, 'II Corinthians 9:12', 'DAILY BREAD', '2corinthians', 'II Corinthians', 9, ARRAY[12], 'For the ministration of this office not only supplies whatever the saints need, but also abounds through many thanksgivings in the Lord.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 13, 'Romans 5:13', 'DAILY BREAD', 'romans', 'Romans', 5, ARRAY[13], 'For even before the law, sin was in the world, but sin was not imputed while the law did not exist.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 14, 'Nahum 2:8', 'DAILY BREAD', 'nahum', 'Nahum', 2, ARRAY[8], 'And Nineveh, her waters are like a fish pond. Yet truly, they have fled away: “Stand, stand!” But there is no one who will turn back.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 15, 'Amos 1:7', 'DAILY BREAD', 'amos', 'Amos', 1, ARRAY[7], 'And I will send a fire onto the wall of Gaza, and it will devour its buildings.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 16, 'Sirach 32:4', 'DAILY BREAD', 'sirach', 'Sirach', 32, ARRAY[4], 'Speak, you who are greater by birth. For it is fitting for you') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 17, 'Micah 7:12', 'DAILY BREAD', 'micah', 'Micah', 7, ARRAY[12], 'In that day also, they will come towards you even from Assur, and even to the fortified cities, and from the fortified cities even to the river, and from sea to sea, and from mountain to mountain.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 18, 'II Maccabees 9:15', 'DAILY BREAD', '2maccabees', 'II Maccabees', 9, ARRAY[15], 'And the Jews, whom he had said he certainly did not consider worthy even to be buried, but would deliver them to be torn apart by birds and wild beasts, and would exterminate them with their little ones, he now promised to make equal with the Athenians.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 19, 'Jonah 2:3', 'DAILY BREAD', 'jonah', 'Jonah', 2, ARRAY[3], 'And he said: “I cried out to the Lord from my tribulation, and he heeded me. From the belly of hell, I cried out, and you heeded my voice.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 20, 'I Chronicles 14:16', 'DAILY BREAD', '1chronicles', 'I Chronicles', 14, ARRAY[16], 'Therefore, David did just as God had instructed him. And he struck down the army of the Philistines, from Gibeon as far as Gazera.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 21, 'Revelation of John 14:10', 'DAILY BREAD', 'revelation', 'Revelation of John', 14, ARRAY[10], 'he shall drink also from the wine of the wrath of God, which has been mixed with strong wine in the cup of his wrath, and he shall be tortured with fire and sulphur in the sight of the holy Angels and before the sight of the Lamb.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 22, 'I Maccabees 6:6', 'DAILY BREAD', '1maccabees', 'I Maccabees', 6, ARRAY[6], 'and that Lysias went forth with a particularly strong army, and he was forced to flee before the face of the Jews, and that they were strengthened by the weapons, and resources, and many spoils which they seized from the camps they demolished,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 23, 'Ezekiel 47:17', 'DAILY BREAD', 'ezekiel', 'Ezekiel', 47, ARRAY[17], 'and the border will be from the sea, even to the entrance of Enon, at the border of Damascus, and from the north to the north, at the border of Hamath, on the northern side.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 24, 'Proverbs 25:6', 'DAILY BREAD', 'proverbs', 'Proverbs', 25, ARRAY[6], 'Do not appear glorious before the king, and do not stand in the place of the great.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 25, 'Romans 6:19', 'DAILY BREAD', 'romans', 'Romans', 6, ARRAY[19], 'I am speaking in human terms because of the infirmity of your flesh. For just as you offered the parts of your body to serve impurity and iniquity, for the sake of iniquity, so also have you now yielded the parts of your body to serve justice, for the sake of sanctification.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 26, 'Judges 16:20', 'DAILY BREAD', 'judges', 'Judges', 16, ARRAY[20], 'And she said, “The Philistines are upon you, Samson!” And awaking from sleep, he said in his mind, “I will break away and shake myself free, just as I did before.” For he did not know that the Lord had withdrawn from him.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 27, 'Revelation of John 22:12', 'DAILY BREAD', 'revelation', 'Revelation of John', 22, ARRAY[12], '“Behold, I am approaching quickly! And my repayment is with me, to render to each one according to his works.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 28, 'Acts 18:23', 'DAILY BREAD', 'acts', 'Acts', 18, ARRAY[23], 'And having spent some length of time there, he set out, and he walked in order through the region of Galatia and Phrygia, strengthening all the disciples.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 29, 'Esther 14:11', 'DAILY BREAD', 'esther', 'Esther', 14, ARRAY[11], 'Lord, do not hand over your scepter to that which does not exist, lest they laugh at our ruin, but turn their counsel upon themselves and destroy him who has begun to rage against us.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 30, 'Nahum 3:13', 'DAILY BREAD', 'nahum', 'Nahum', 3, ARRAY[13], 'Behold, women are at the center of your people. The gates of your land will be opened wide for your enemies; fire will devour your bars.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 31, 'Proverbs 26:19', 'DAILY BREAD', 'proverbs', 'Proverbs', 26, ARRAY[19], 'so also is the man who harms his friend by deceitfulness. And when he has been apprehended, he says, “I did it jokingly.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 32, 'I Timothy 5:12', 'DAILY BREAD', '1timothy', 'I Timothy', 5, ARRAY[12], 'resulting in damnation, because they have disregarded the primacy of faith.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 33, 'Numbers 18:8', 'DAILY BREAD', 'numbers', 'Numbers', 18, ARRAY[8], 'And the Lord said to Aaron: “Behold, I have given you custody of my first-fruits. Everything that is sanctified by the sons of Israel I have delivered to you and your sons, for the office of the priesthood, by everlasting ordinances.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 34, 'Numbers 3:39', 'DAILY BREAD', 'numbers', 'Numbers', 3, ARRAY[39], 'All the Levites, whom Moses and Aaron numbered by their families according to the precept of the Lord, of the male gender, from one month and above, were twenty-two thousand.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 35, 'Hebrews 5:5', 'DAILY BREAD', 'hebrews', 'Hebrews', 5, ARRAY[5], 'Thus, even Christ did not glorify himself, so as to become High Priest, but instead, it was God who said to him: “You are my Son. Today I have begotten you.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 36, 'I Peter 2:13', 'DAILY BREAD', '1peter', 'I Peter', 2, ARRAY[13], 'Therefore, be subject to every human creature because of God, whether it is to the king as preeminent,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 37, 'Exodus 21:2', 'DAILY BREAD', 'exodus', 'Exodus', 21, ARRAY[2], 'If you buy a Hebrew servant, six years shall he serve you; in the seventh, he shall depart freely, without charge.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 38, 'Proverbs 1:7', 'DAILY BREAD', 'proverbs', 'Proverbs', 1, ARRAY[7], 'The fear of the Lord is the beginning of wisdom. The foolish despise wisdom as well as doctrine.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 39, 'Malachi 3:13', 'DAILY BREAD', 'malachi', 'Malachi', 3, ARRAY[13], 'Your words have gathered strength over me, says the Lord.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 40, 'Jonah 1:6', 'DAILY BREAD', 'jonah', 'Jonah', 1, ARRAY[6], 'And the helmsman approached him, and he said to him, “Why are you weighed down with sleep? Rise, call upon your God, so perhaps God will be mindful of us and we might not perish.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 41, 'Titus 1:10', 'DAILY BREAD', 'titus', 'Titus', 1, ARRAY[10], 'For there are, indeed, many who are disobedient, who speak empty words, and who deceive, especially those who are of the circumcision.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 42, 'James 1:25', 'DAILY BREAD', 'james', 'James', 1, ARRAY[25], 'But he who gazes upon the perfect law of liberty, and who remains in it, is not a forgetful hearer, but instead a doer of the work. He shall be blessed in what he does.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 43, 'Proverbs 26:11', 'DAILY BREAD', 'proverbs', 'Proverbs', 26, ARRAY[11], 'Like a dog that returns to his vomit, so also is the imprudent who repeats his foolishness.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 44, 'Hosea 6:1', 'DAILY BREAD', 'hosea', 'Hosea', 6, ARRAY[1], 'In their tribulation, they will arise early to me. Come, let us return to the Lord.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 45, 'Malachi 3:13', 'DAILY BREAD', 'malachi', 'Malachi', 3, ARRAY[13], 'Your words have gathered strength over me, says the Lord.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 46, 'Amos 1:14', 'DAILY BREAD', 'amos', 'Amos', 1, ARRAY[14], 'And I will ignite a fire on the wall of Rabbah. And it will devour its buildings, with wailing on the day of war, and with a whirlwind on the day of commotion.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 47, 'Daniel 1:20', 'DAILY BREAD', 'daniel', 'Daniel', 1, ARRAY[20], 'And in every concept of wisdom and understanding, about which the king consulted with them, he found them to be ten times better than all the seers and astrologers put together, who were in his entire kingdom.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 48, 'II Thessalonians 2:2', 'DAILY BREAD', '2thessalonians', 'II Thessalonians', 2, ARRAY[2], 'that you not be readily disturbed or terrified in your minds, by any spirit, or word, or epistle, supposedly sent from us, claiming that the day of the Lord is close by.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 49, 'Ezekiel 5:11', 'DAILY BREAD', 'ezekiel', 'Ezekiel', 5, ARRAY[11], 'Therefore, as I myself live says the Lord God, because you have violated my sanctuary with all your offenses and with all your abominations, I also will break into pieces, and my eye will not be lenient, and I will not take pity.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 50, 'Zechariah 14:9', 'DAILY BREAD', 'zechariah', 'Zechariah', 14, ARRAY[9], 'And the Lord will be King over all the earth. In that day, there will be one Lord, and his name will be one.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 51, 'I Corinthians 1:1', 'DAILY BREAD', '1corinthians', 'I Corinthians', 1, ARRAY[1], 'Paul, called as an Apostle of Jesus Christ by the will of God; and Sosthenes, a brother:') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 52, 'Micah 4:7', 'DAILY BREAD', 'micah', 'Micah', 4, ARRAY[7], 'And I will place the lame within the remnant, and she who had been in distress, within a healthy people. And the Lord will reign over them on Mount Zion, from the present time and even unto eternity.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 53, 'II Timothy 2:21', 'DAILY BREAD', '2timothy', 'II Timothy', 2, ARRAY[21], 'If anyone, then, will have cleansed himself from these things, he shall be a vessel held in honor, sanctified and useful to the Lord, prepared for every good work.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 54, 'Nehemiah 12:16', 'DAILY BREAD', 'nehemiah', 'Nehemiah', 12, ARRAY[16], 'of Adaiah, Zechariah; of Ginnethon, Meshullam;') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 55, 'Joel 1:11', 'DAILY BREAD', 'joel', 'Joel', 1, ARRAY[11], 'The farmers have been confounded, the vineyard workers have wailed over the crop and the barley, because the harvest of the field has perished.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 56, 'Haggai 1:7', 'DAILY BREAD', 'haggai', 'Haggai', 1, ARRAY[7], 'Thus says the Lord of hosts: Set your hearts upon your ways.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 57, 'Genesis 43:27', 'DAILY BREAD', 'genesis', 'Genesis', 43, ARRAY[27], 'But he, gently greeting them again, questioned them, saying: “Is your father, the old man about whom you spoke to me, in good health? Is he still alive?”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 58, 'James 5:11', 'DAILY BREAD', 'james', 'James', 5, ARRAY[11], 'Consider that we beatify those who have endured. You have heard of the patient suffering of Job. And you have seen the end of the Lord, that the Lord is merciful and compassionate.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 59, 'Esther 9:6', 'DAILY BREAD', 'esther', 'Esther', 9, ARRAY[6], 'so much so that even in Susa they executed five hundred men, besides the ten sons of Haman the Agagite, the enemy of the Jews, and their names are these:') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 60, 'Philemon 1:7', 'DAILY BREAD', 'philemon', 'Philemon', 1, ARRAY[7], 'For I have found great joy and consolation in your charity, because the hearts of the saints have been refreshed by you, brother.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 61, 'Acts 5:29', 'DAILY BREAD', 'acts', 'Acts', 5, ARRAY[29], 'But Peter and the Apostles responded by saying: “It is necessary to obey God, more so than men.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 62, 'Baruch 6:36', 'DAILY BREAD', 'baruch', 'Baruch', 6, ARRAY[36], 'They cannot restore sight to the blind, nor free a man from need.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 63, 'Titus 3:13', 'DAILY BREAD', 'titus', 'Titus', 3, ARRAY[13], 'Send Zenas the lawyer and Apollo ahead with care, and let nothing be lacking to them.') ON CONFLICT (date) DO NOTHING;
