  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 66, 'Nahum 3:11', 'DAILY BREAD', 'nahum', 'Nahum', 3, ARRAY[11], 'Therefore, you also will become inebriated, and you will be despised, and you will seek help from the opposition.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 67, 'Ezra 2:17', 'DAILY BREAD', 'ezra', 'Ezra', 2, ARRAY[17], 'The sons of Bezai, three hundred twenty-three.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 68, 'Romans 6:4', 'DAILY BREAD', 'romans', 'Romans', 6, ARRAY[4], 'For through baptism we have been buried with him into death, so that, in the manner that Christ rose from the dead, by the glory of the Father, so may we also walk in the newness of life.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 69, 'I Corinthians 9:11', 'DAILY BREAD', '1corinthians', 'I Corinthians', 9, ARRAY[11], 'If we have sown spiritual things in you, is it important if we harvest from your worldly things?') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 70, 'Joshua 24:28', 'DAILY BREAD', 'joshua', 'Joshua', 24, ARRAY[28], 'And he dismissed the people, each one to their own possession.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 71, 'I Peter 3:16', 'DAILY BREAD', '1peter', 'I Peter', 3, ARRAY[16], 'But do so with meekness and fear, having a good conscience, so that, in whatever matter they may slander you, they shall be confounded, since they falsely accuse your good behavior in Christ.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 72, 'Philippians 1:3', 'DAILY BREAD', 'philippians', 'Philippians', 1, ARRAY[3], 'I give thanks to my God, with every remembrance of you,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 73, 'Ruth 1:15', 'DAILY BREAD', 'ruth', 'Ruth', 1, ARRAY[15], 'Naomi said to her, “See, your kinswoman returns to her people, and to her gods. Hurry after her.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 74, 'Habakkuk 2:20', 'DAILY BREAD', 'habakkuk', 'Habakkuk', 2, ARRAY[20], 'But the Lord is in his holy temple. May all the earth be silent before his face.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 75, 'Daniel 12:5', 'DAILY BREAD', 'daniel', 'Daniel', 12, ARRAY[5], 'And I, Daniel, looked, and behold, similarly two others stood up, one over here, on the bank of the river, and the other over there, on the other bank of the river.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 76, 'Zechariah 8:15', 'DAILY BREAD', 'zechariah', 'Zechariah', 8, ARRAY[15], 'and I did not show mercy, so have I turned back, thinking in these days to do good to the house of Judah and to Jerusalem. Do not be afraid.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 77, 'Daniel 11:11', 'DAILY BREAD', 'daniel', 'Daniel', 11, ARRAY[11], 'And the king of the South, having being challenged, will go forth and will fight against the king of the North, and he will prepare an exceedingly great multitude, and a multitude will be given into his hand.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 78, 'Song of Solomon 7:8', 'DAILY BREAD', 'song', 'Song of Solomon', 7, ARRAY[8], 'Your stature is comparable to the palm tree, and your breasts to clusters of grapes.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 79, 'Judges 9:18', 'DAILY BREAD', 'judges', 'Judges', 9, ARRAY[18], 'though you now have risen up against my father’s house, and have killed his sons, seventy men, upon one stone, and have appointed Abimelech, the son of his handmaid, as a king over the inhabitants of Shechem, since he is your brother,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 80, 'Judges 16:30', 'DAILY BREAD', 'judges', 'Judges', 16, ARRAY[30], 'he said, “May my life die with the Philistines.” And when he had shaken the pillars strongly, the house fell upon all the leaders, and the rest of the multitude who were there. And he killed many more in his death than he had killed before in his life.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 81, 'Zechariah 3:1', 'DAILY BREAD', 'zechariah', 'Zechariah', 3, ARRAY[1], 'And the Lord revealed to me: Jesus the high priest, standing in the sight of the angel of the Lord. And Satan stood before his right hand, so as to be his adversary.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 82, 'Leviticus 27:22', 'DAILY BREAD', 'leviticus', 'Leviticus', 27, ARRAY[22], 'If a field has been bought, and it is not from the possession of ancestors, it shall be sanctified to the Lord.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 83, 'Ephesians 4:24', 'DAILY BREAD', 'ephesians', 'Ephesians', 4, ARRAY[24], 'and so put on the new man, who, in accord with God, is created in justice and in the holiness of truth.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 84, 'Zechariah 4:9', 'DAILY BREAD', 'zechariah', 'Zechariah', 4, ARRAY[9], 'The hand of Zerubbabel has founded this house, and his hands will complete it. And you will know that the Lord of hosts has sent me to you.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 85, 'Jude 1:3', 'DAILY BREAD', 'jude', 'Jude', 1, ARRAY[3], 'Most beloved, taking all care to write to you about your common salvation, I found it necessary to write to you in order to beg you to contend earnestly for the faith that was handed down once to the saints.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 86, 'Jonah 1:6', 'DAILY BREAD', 'jonah', 'Jonah', 1, ARRAY[6], 'And the helmsman approached him, and he said to him, “Why are you weighed down with sleep? Rise, call upon your God, so perhaps God will be mindful of us and we might not perish.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 87, 'Ruth 4:8', 'DAILY BREAD', 'ruth', 'Ruth', 4, ARRAY[8], 'And so Boaz said to his kinsman, “Take off your shoe.” And immediately he released it from his foot.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 88, 'James 5:17', 'DAILY BREAD', 'james', 'James', 5, ARRAY[17], 'Elijah was a mortal man like us, and in prayer he prayed that it would not rain upon the earth. And it did not rain for three years and six months.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 89, 'Jeremiah 46:22', 'DAILY BREAD', 'jeremiah', 'Jeremiah', 46, ARRAY[22], 'Her voice will sound out like brass. For they will rush forward with an army, and with axes they will come against her, like those who chop wood.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 90, 'Joshua 10:9', 'DAILY BREAD', 'joshua', 'Joshua', 10, ARRAY[9], 'And so Joshua, ascending from Gilgal throughout the night, rushed upon them suddenly.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 91, 'Matthew 28:8', 'DAILY BREAD', 'matthew', 'Matthew', 28, ARRAY[8], 'And they went out of the tomb quickly, with fear and in great joy, running to announce it to his disciples.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 92, 'II Samuel 15:30', 'DAILY BREAD', '2samuel', 'II Samuel', 15, ARRAY[30], 'But David ascended to the Mount of Olives, climbing and weeping, advancing with bare feet and with his head covered. Moreover, all the people who were with him ascended, weeping with their heads covered.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 93, 'Judges 2:5', 'DAILY BREAD', 'judges', 'Judges', 2, ARRAY[5], 'And the name of that place was called, the Place of Weeping, or the Place of Tears. And they immolated victims to the Lord in that place.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 94, 'Nahum 2:13', 'DAILY BREAD', 'nahum', 'Nahum', 2, ARRAY[13], 'Behold, I will come to you, says the Lord of hosts, and I will burn your chariots even to smoke, and the sword will devour your young lions. And I will exterminate your prey from the land, and the voice of your messengers shall no longer be heard.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 95, 'Ezra 6:17', 'DAILY BREAD', 'ezra', 'Ezra', 6, ARRAY[17], 'And they offered, for the dedication of the house of God, one hundred calves, two hundred rams, four hundred lambs, and, as a sin offering for all of Israel, twelve he-goats from among the goats, according to the number of the tribes of Israel.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 96, 'John 4:9', 'DAILY BREAD', 'john', 'John', 4, ARRAY[9], 'And so, that Samaritan woman said to him, “How is it that you, being a Jew, are requesting a drink from me, though I am a Samaritan woman?” For the Jews do not associate with the Samaritans.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 97, 'Revelation of John 2:10', 'DAILY BREAD', 'revelation', 'Revelation of John', 2, ARRAY[10], 'You should fear nothing amid those things which you will suffer. Behold, the devil will cast some of you into prison, so that you may be tested. And you will have tribulation for ten days. Be faithful even unto death, and I will give to you the crown of life.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 98, 'Nahum 2:2', 'DAILY BREAD', 'nahum', 'Nahum', 2, ARRAY[2], 'For the Lord has repaid the arrogance of Jacob, just like the arrogance of Israel. For the despoilers have scattered them, and they have corrupted their procreation.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 99, 'I Peter 4:11', 'DAILY BREAD', '1peter', 'I Peter', 4, ARRAY[11], 'When anyone speaks, it should be like words of God. When anyone ministers, it should be from the virtue that God provides, so that in all things God may be honored through Jesus Christ. To him is glory and dominion forever and ever. Amen.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 100, 'Acts 5:22', 'DAILY BREAD', 'acts', 'Acts', 5, ARRAY[22], 'But when the attendants had arrived, and, upon opening the prison, had not found them, they returned and reported to them,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 101, 'II Thessalonians 1:3', 'DAILY BREAD', '2thessalonians', 'II Thessalonians', 1, ARRAY[3], 'We ought to give thanks always to God for you, brothers, in a fitting manner, because your faith is increasing greatly, and because the charity of each of you toward one another is abundant,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 102, 'Ezra 1:8', 'DAILY BREAD', 'ezra', 'Ezra', 1, ARRAY[8], 'Now Cyrus, king of Persia, offered these by the hand of Mithredath, the son of the treasurer, and he counted these out to Sheshbazzar, the leader of Judah.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 103, 'Mark 6:30', 'DAILY BREAD', 'mark', 'Mark', 6, ARRAY[30], 'And the Apostles, returning to Jesus, reported to him everything that they had done and taught.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 104, 'Tobit 3:8', 'DAILY BREAD', 'tobit', 'Tobit', 3, ARRAY[8], 'For she had been given to seven husbands, and a demon named Asmodeus had killed them, as soon as they had approached her.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 105, 'III John 1:4', 'DAILY BREAD', '3john', 'III John', 1, ARRAY[4], 'I have no greater grace than this, when I hear that my sons are walking in the truth.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 106, 'John 18:7', 'DAILY BREAD', 'john', 'John', 18, ARRAY[7], 'Then again he questioned them: “Who are you seeking?” And they said, “Jesus the Nazarene.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 107, 'Ephesians 2:14', 'DAILY BREAD', 'ephesians', 'Ephesians', 2, ARRAY[14], 'For he is our peace. He made the two into one, by dissolving the intermediate wall of separation, of opposition, by his flesh,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 108, 'II Corinthians 10:9', 'DAILY BREAD', '2corinthians', 'II Corinthians', 10, ARRAY[9], 'But let it not be said that I am scaring you by means of epistles.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 109, 'II Peter 1:10', 'DAILY BREAD', '2peter', 'II Peter', 1, ARRAY[10], 'Because of this, brothers, be all the more diligent, so that by good works you may make certain your calling and election. For in doing these things, you do not sin at any time.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 110, 'II Chronicles 24:8', 'DAILY BREAD', '2chronicles', 'II Chronicles', 24, ARRAY[8], 'Therefore, the king instructed, and they made an ark. And they placed it beside the gate of the house of the Lord, on the outside.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 111, 'II Samuel 9:12', 'DAILY BREAD', '2samuel', 'II Samuel', 9, ARRAY[12], 'Now Mephibosheth had a young son whose name was Mica. Truly, all the kindred of the house of Ziba served Mephibosheth.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 112, 'Nehemiah 13:17', 'DAILY BREAD', 'nehemiah', 'Nehemiah', 13, ARRAY[17], 'And I put the nobles of Judah under oath, and I said to them: “What is this evil thing that you are doing, profaning the Sabbath day?') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 113, 'Philemon 1:2', 'DAILY BREAD', 'philemon', 'Philemon', 1, ARRAY[2], 'and to Apphia, most beloved sister, and to Archippus, our fellow soldier, and to the church which is in your house.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 114, 'Hosea 9:6', 'DAILY BREAD', 'hosea', 'Hosea', 9, ARRAY[6], 'For, behold, they have been sent away by devastation. Egypt will gather them together; Memphis will bury them. Nettles will inherit their desired silver; the burr will be in their tabernacles.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 115, 'Daniel 3:50', 'DAILY BREAD', 'daniel', 'Daniel', 3, ARRAY[50], 'And he made the middle of the furnace like the blowing of a damp wind, and the fire did not touch them, nor afflict them, nor bother them at all.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 116, 'II Kings 1:11', 'DAILY BREAD', '2kings', 'II Kings', 1, ARRAY[11], 'And again, he sent to him another leader of fifty, and the fifty with him. And he said to him, “Man of God, thus says the king: Hurry, descend.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 117, 'Deuteronomy 29:27', 'DAILY BREAD', 'deuteronomy', 'Deuteronomy', 29, ARRAY[27], 'For this reason, the fury of the Lord was enraged against this land, so as to lead over it all the curses which have been written in this volume.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 118, 'Ephesians 3:8', 'DAILY BREAD', 'ephesians', 'Ephesians', 3, ARRAY[8], 'Although I am the least of all the saints, I have been given this grace: to evangelize among the Gentiles the unsearchable riches of Christ,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 119, 'John 3:2', 'DAILY BREAD', 'john', 'John', 3, ARRAY[2], 'He went to Jesus at night, and he said to him: “Rabbi, we know that you have arrived as a teacher from God. For no one would be able to accomplish these signs, which you accomplish, unless God were with him.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 120, 'II Corinthians 13:6', 'DAILY BREAD', '2corinthians', 'II Corinthians', 13, ARRAY[6], 'But I hope you know that we ourselves are not reprobates.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 121, 'I Corinthians 5:1', 'DAILY BREAD', '1corinthians', 'I Corinthians', 5, ARRAY[1], 'Above all else, it is being said that there is fornication among you, even fornication of a such kind that is not among the Gentiles, so that someone would have the wife of his father.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 122, 'Revelation of John 9:8', 'DAILY BREAD', 'revelation', 'Revelation of John', 9, ARRAY[8], 'And they had hair like the hair of women. And their teeth were like the teeth of lions.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 123, 'Micah 4:13', 'DAILY BREAD', 'micah', 'Micah', 4, ARRAY[13], 'Rise and thresh, daughter of Zion. For I will set your horn like iron, and I will set your hoofs like brass. And you will shatter many peoples, and you will immolate their spoils for the Lord, and their strength for the Lord of the whole earth.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 124, 'I Timothy 4:2', 'DAILY BREAD', '1timothy', 'I Timothy', 4, ARRAY[2], 'speaking lies in hypocrisy, and having their consciences seared,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 125, 'II Corinthians 2:16', 'DAILY BREAD', '2corinthians', 'II Corinthians', 2, ARRAY[16], 'To the one, certainly, the fragrance is of death unto death. But to the other, the fragrance is of life unto life. And concerning these things, who is so suitable?') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 126, 'Ecclesiastes 10:14', 'DAILY BREAD', 'ecclesiastes', 'Ecclesiastes', 10, ARRAY[14], 'The fool multiplies his words. A man does not know what has been before him, and who is able to reveal to him what will be in the future after him?') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 127, 'Titus 1:16', 'DAILY BREAD', 'titus', 'Titus', 1, ARRAY[16], 'They claim that they know God. But, by their own works, they deny him, since they are abominable, and unbelieving, and reprobate, toward every good work.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 128, 'Hosea 1:4', 'DAILY BREAD', 'hosea', 'Hosea', 1, ARRAY[4], 'And the Lord said to him: “Call his name Jezreel because, after a little while, I will visit the blood of Jezreel upon the house of Jehu, and I will put the kingdom of the house of Israel to rest.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 129, 'I Thessalonians 5:16', 'DAILY BREAD', '1thessalonians', 'I Thessalonians', 5, ARRAY[16], 'Rejoice always.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 130, 'Job 25:4', 'DAILY BREAD', 'job', 'Job', 25, ARRAY[4], 'Is it right for man to compare himself to God, or to appear pure though he is born of woman?') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 131, 'Ezra 9:1', 'DAILY BREAD', 'ezra', 'Ezra', 9, ARRAY[1], 'Then, after these things were completed, the leaders came to me, saying: “The people of Israel, the priests, and the Levites, have not been separated from the peoples of the lands and from their abominations, especially those of the Canaanites, and Hittites, and Perizzites, and Jebusites, and Ammonites, and Moabites, and Egyptians, and Amorites.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 132, 'Sirach 23:12', 'DAILY BREAD', 'sirach', 'Sirach', 23, ARRAY[12], 'A man who swears many oaths will be filled with iniquity, and scourges will not depart from his house.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 133, 'Lamentations 3:15', 'DAILY BREAD', 'lamentations', 'Lamentations', 3, ARRAY[15], 'HE. He has filled me with bitterness; he has inebriated me with wormwood.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 134, 'Numbers 18:22', 'DAILY BREAD', 'numbers', 'Numbers', 18, ARRAY[22], 'so that the sons of Israel may no longer approach to the tabernacle, nor commit deadly sin.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 135, 'I Thessalonians 1:6', 'DAILY BREAD', '1thessalonians', 'I Thessalonians', 1, ARRAY[6], 'And so, you became imitators of us and of the Lord, accepting the Word in the midst of great tribulation, but with the joy of the Holy Spirit.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 136, 'I Maccabees 1:60', 'DAILY BREAD', '1maccabees', 'I Maccabees', 1, ARRAY[60], 'And all those who were found with the books of the testament of the Lord, and whoever observed the law of the Lord, they butchered, according to the edict of the king.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 137, 'Ruth 2:16', 'DAILY BREAD', 'ruth', 'Ruth', 2, ARRAY[16], 'and purposely let fall some from your bundles, and allow them to remain, so that she may gather without blushing, and let no one rebuke her gathering.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 138, 'James 5:5', 'DAILY BREAD', 'james', 'James', 5, ARRAY[5], 'You have feasted upon the earth, and you have nourished your hearts with luxuries, unto the day of slaughter.') ON CONFLICT (date) DO NOTHING;
