  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 140, 'Ezekiel 14:19', 'DAILY BREAD', 'ezekiel', 'Ezekiel', 14, ARRAY[19], 'Then, if I also send the pestilence upon that land, and I pour out my indignation upon it with blood, so that I take away from it both man and beast,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 141, 'Nahum 3:14', 'DAILY BREAD', 'nahum', 'Nahum', 3, ARRAY[14], 'Draw in water because of the blockade; build up your fortresses. Go into the clay and tread; work it to make brick.') ON CONFLICT (date) DO NOTHING;
