  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 148, 'Luke 18:30', 'DAILY BREAD', 'luke', 'Luke', 18, ARRAY[30], 'who will not receive much more in this time, and in the age to come eternal life.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 149, 'Philippians 4:4', 'DAILY BREAD', 'philippians', 'Philippians', 4, ARRAY[4], 'Rejoice in the Lord always. Again, I say, rejoice.') ON CONFLICT (date) DO NOTHING;
