  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 152, 'Philemon 1:25', 'DAILY BREAD', 'philemon', 'Philemon', 1, ARRAY[25], 'May the grace of our Lord Jesus Christ be with your spirit. Amen.') ON CONFLICT (date) DO NOTHING;
