  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 154, 'Mark 4:22', 'DAILY BREAD', 'mark', 'Mark', 4, ARRAY[22], 'For there is nothing hidden that will not be revealed. Neither was anything done in secret, except that it may be made public.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 155, 'I Samuel 30:19', 'DAILY BREAD', '1samuel', 'I Samuel', 30, ARRAY[19], 'And nothing was missing, from small even to great, among the sons and daughters, and among the spoils, and among everything whatsoever that they had seized. David returned it all.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 156, 'Jonah 4:7', 'DAILY BREAD', 'jonah', 'Jonah', 4, ARRAY[7], 'And God prepared a worm, when dawn approached on the next day, and it struck the ivy, and it dried up.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 157, 'Judith 8:21', 'DAILY BREAD', 'judith', 'Judith', 8, ARRAY[21], 'And now, brothers, because you are the elders among the people of God, and their very soul hangs upon you, rescue their hearts by your eloquence, so that they may remember that our fathers were tested in order to prove whether or not they truly worshiped their God.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 158, 'Ecclesiastes 12:8', 'DAILY BREAD', 'ecclesiastes', 'Ecclesiastes', 12, ARRAY[8], 'Vanity of vanities, said Ecclesiastes, and all is vanity!') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 159, 'Leviticus 15:20', 'DAILY BREAD', 'leviticus', 'Leviticus', 15, ARRAY[20], 'All who will touch her shall be unclean until evening.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 160, 'Amos 3:10', 'DAILY BREAD', 'amos', 'Amos', 3, ARRAY[10], 'And they do not know how to make it right, says the Lord, storing up iniquity and plunder in their buildings.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 161, 'Sirach 23:1', 'DAILY BREAD', 'sirach', 'Sirach', 23, ARRAY[1], 'Lord, Father and Ruler of my life: may you not abandon me to their counsel, nor permit me to fall by them.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 162, 'I Maccabees 10:78', 'DAILY BREAD', '1maccabees', 'I Maccabees', 10, ARRAY[78], 'And he went toward Azotus, like one making a journey, but he suddenly departed into the plains, because he had a great number of horsemen, and he trusted in them. And Jonathan followed after him to Azotus, and they joined together in battle.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 163, 'Acts 1:16', 'DAILY BREAD', 'acts', 'Acts', 1, ARRAY[16], '“Noble brothers, the Scripture must be fulfilled, which the Holy Spirit predicted by the mouth of David about Judas, who was the leader of those who apprehended Jesus.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 164, 'I Kings 16:24', 'DAILY BREAD', '1kings', 'I Kings', 16, ARRAY[24], 'And he bought the mount of Samaria from Shemer for two talents of silver. And he built upon it, and he called the name of the city that he had built, Samaria, after the name of Shemer, the owner of the mount.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 165, 'Zechariah 10:10', 'DAILY BREAD', 'zechariah', 'Zechariah', 10, ARRAY[10], 'And I will lead them back from the land of Egypt, and I will gather them from among the Assyrians, and I will lead them to the land of Gilead and Lebanon, and no place will be left that has not been found by them.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 166, 'Esther 15:11', 'DAILY BREAD', 'esther', 'Esther', 15, ARRAY[11], 'And God changed the king’s spirit into gentleness; quickly and apprehensively, he leapt from his throne, and lifting her up in his arms until she came to herself, he coaxed her with these words:') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 167, 'Nahum 3:15', 'DAILY BREAD', 'nahum', 'Nahum', 3, ARRAY[15], 'There, fire will devour you. You will perish by the sword; it will devour you like the beetle. Gather together like the beetle. Multiply like the locust.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 168, 'Tobit 8:2', 'DAILY BREAD', 'tobit', 'Tobit', 8, ARRAY[2], 'And so, Tobias, remembering the word of the Angel, took part of the liver from his bag, and he placed it over the live coals.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 169, 'Proverbs 23:1', 'DAILY BREAD', 'proverbs', 'Proverbs', 23, ARRAY[1], 'When you sit down to eat with a leader, pay close attention to what has been set before your face,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 170, 'John 18:13', 'DAILY BREAD', 'john', 'John', 18, ARRAY[13], 'And they led him away, first to Annas, for he was the father-in-law of Caiaphas, who was the high priest that year.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 171, 'Proverbs 21:9', 'DAILY BREAD', 'proverbs', 'Proverbs', 21, ARRAY[9], 'It is better to sit in a corner of the attic, than with a contentious woman and in a shared house.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 172, 'I John 5:20', 'DAILY BREAD', '1john', 'I John', 5, ARRAY[20], 'And we know that the Son of God has arrived, and that he has given us understanding, so that we may know the true God, and so that we may remain in his true Son. This is the true God, and this is Eternal Life.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 173, 'II Chronicles 6:13', 'DAILY BREAD', '2chronicles', 'II Chronicles', 6, ARRAY[13], 'For indeed, Solomon had made a bronze base, and he had positioned it in the midst of the hall; it held five cubits in length, and five cubits in width, and three cubits in height. And he stood upon it. And next, kneeling down while facing the entire multitude of Israel, and lifting up his palms towards heaven,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 174, 'Psalms 138:9', 'DAILY BREAD', 'psalms', 'Psalms', 138, ARRAY[9], 'If I assume my feathers in early morning, and dwell in the utmost parts of the sea,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 175, 'Hebrews 10:20', 'DAILY BREAD', 'hebrews', 'Hebrews', 10, ARRAY[20], 'and in the new and living Way, which he has initiated for us by the veil, that is, by his flesh,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 176, 'Genesis 33:12', 'DAILY BREAD', 'genesis', 'Genesis', 33, ARRAY[12], 'he said, “Let us go on together, and I will accompany you on your journey.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 177, 'Matthew 22:30', 'DAILY BREAD', 'matthew', 'Matthew', 22, ARRAY[30], 'For in the resurrection, they shall neither marry, nor be given in marriage. Instead, they shall be like the Angels of God in heaven.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 178, 'Ruth 2:7', 'DAILY BREAD', 'ruth', 'Ruth', 2, ARRAY[7], 'and she asked to gather the remnants of the ears of grain, following the steps of the reapers, and from morning until now she has remained in the field, and, indeed, not for one moment has she returned home.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 179, 'Matthew 28:8', 'DAILY BREAD', 'matthew', 'Matthew', 28, ARRAY[8], 'And they went out of the tomb quickly, with fear and in great joy, running to announce it to his disciples.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 180, 'Titus 2:3', 'DAILY BREAD', 'titus', 'Titus', 2, ARRAY[3], 'Old women, similarly, should be in holy attire, not false accusers, not given to much wine, teaching well,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 181, 'Haggai 2:17', 'DAILY BREAD', 'haggai', 'Haggai', 2, ARRAY[17], 'when you approached a pile of twenty measures, and they became ten, and you entered to the press, to press out fifty bottles, and they became twenty,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 182, 'I Thessalonians 4:4', 'DAILY BREAD', '1thessalonians', 'I Thessalonians', 4, ARRAY[4], 'that each one of you should know how to possess his vessel in sanctification and honor,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 183, 'Psalms 47:2', 'DAILY BREAD', 'psalms', 'Psalms', 47, ARRAY[2], 'The Lord is great and exceedingly praiseworthy, in the city of our God, on his holy mountain.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 184, 'Nehemiah 4:1', 'DAILY BREAD', 'nehemiah', 'Nehemiah', 4, ARRAY[1], 'Now it happened that, when Sanballat had heard that we were building the wall, he was very angry. And having been moved exceedingly, he ridiculed the Jews.') ON CONFLICT (date) DO NOTHING;
