  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 187, 'Joel 1:14', 'DAILY BREAD', 'joel', 'Joel', 1, ARRAY[14], 'Sanctify a fast, call an assembly, gather the elders and all the inhabitants of the land into the house of your God. And cry out to the Lord:') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 188, 'Psalms 103:31', 'DAILY BREAD', 'psalms', 'Psalms', 103, ARRAY[31], 'May the glory of the Lord be for all ages. The Lord will rejoice in his works.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 189, 'III John 1:15', 'DAILY BREAD', '3john', 'III John', 1, ARRAY[15], '') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 190, 'Habakkuk 2:19', 'DAILY BREAD', 'habakkuk', 'Habakkuk', 2, ARRAY[19], 'Woe to him who says to wood, “Awaken,” to the silent stone, “Arise.” Is it able to teach? Behold, it has been entirely covered with gold and silver; and there is no spirit at all in its inner workings.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 191, 'Nehemiah 6:6', 'DAILY BREAD', 'nehemiah', 'Nehemiah', 6, ARRAY[6], '“It has been heard among the Gentiles, and Geshem has said it, that you and the Jews are planning to rebel, and because of this, you are building the wall and thinking to raise yourself as a king over them. For this reason,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 192, 'II Peter 3:13', 'DAILY BREAD', '2peter', 'II Peter', 3, ARRAY[13], 'Yet truly, in accord with his promises, we are looking forward to the new heavens and the new earth, in which justice lives.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 193, 'Numbers 36:5', 'DAILY BREAD', 'numbers', 'Numbers', 36, ARRAY[5], 'Moses answered the sons of Israel, and, at the instruction of the Lord, he said: “The tribe of the sons of Joseph has spoken correctly.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 194, 'I Corinthians 3:21', 'DAILY BREAD', '1corinthians', 'I Corinthians', 3, ARRAY[21], 'And so, let no one glory in men.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 195, 'Matthew 18:15', 'DAILY BREAD', 'matthew', 'Matthew', 18, ARRAY[15], 'But if your brother has sinned against you, go and correct him, between you and him alone. If he listens to you, you will have regained your brother.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 196, 'II Timothy 4:16', 'DAILY BREAD', '2timothy', 'II Timothy', 4, ARRAY[16], 'At my first defense, no one stood by me, but everyone abandoned me. May it not be counted against them!') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 197, 'I Kings 15:32', 'DAILY BREAD', '1kings', 'I Kings', 15, ARRAY[32], 'And there was war between Asa and Baasha, the king of Israel, during all their days.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 198, 'Hebrews 1:5', 'DAILY BREAD', 'hebrews', 'Hebrews', 1, ARRAY[5], 'For to which of the Angels has he ever said: “You are my Son; today have I begotten you?” Or again: “I will be a Father to him, and he shall be a Son to me?”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 199, 'I John 5:2', 'DAILY BREAD', '1john', 'I John', 5, ARRAY[2], 'In this way, we know that we love those born of God: when we love God and do his commandments.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 200, 'I Peter 1:23', 'DAILY BREAD', '1peter', 'I Peter', 1, ARRAY[23], 'For you have been born again, not from corruptible seed, but from what is incorruptible, from the Word of God, living and remaining for all eternity.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 201, 'Amos 7:11', 'DAILY BREAD', 'amos', 'Amos', 7, ARRAY[11], 'For Amos says this: ‘Jeroboam will die by the sword, and Israel will be taken captive out of their own land.’ ”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 202, 'I Timothy 1:7', 'DAILY BREAD', '1timothy', 'I Timothy', 1, ARRAY[7], 'desiring to be teachers of the law, but understanding neither the things that they themselves are saying, nor what they are affirming about these things.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 203, 'I John 3:4', 'DAILY BREAD', '1john', 'I John', 3, ARRAY[4], 'Everyone who commits a sin, also commits iniquity. For sin is iniquity.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 204, 'Genesis 50:19', 'DAILY BREAD', 'genesis', 'Genesis', 50, ARRAY[19], 'And he answered them: “Do not be afraid. Are we able to resist the will of God?') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 205, 'Joshua 8:23', 'DAILY BREAD', 'joshua', 'Joshua', 8, ARRAY[23], 'Also, they apprehended the king of the city of Ai, alive, and they brought him before Joshua.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 206, 'II Timothy 4:7', 'DAILY BREAD', '2timothy', 'II Timothy', 4, ARRAY[7], 'I have fought the good fight. I have completed the course. I have preserved the faith.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 207, 'Nahum 2:7', 'DAILY BREAD', 'nahum', 'Nahum', 2, ARRAY[7], 'And the foot soldier has been led away captive, and her handmaids were driven away, mourning like doves, murmuring in their hearts.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 208, 'II Timothy 3:5', 'DAILY BREAD', '2timothy', 'II Timothy', 3, ARRAY[5], 'even having the appearance of piety while rejecting its virtue. And so, avoid them.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 209, 'Colossians 3:24', 'DAILY BREAD', 'colossians', 'Colossians', 3, ARRAY[24], 'For you know that you will receive from the Lord the repayment of an inheritance. Serve Christ the Lord.') ON CONFLICT (date) DO NOTHING;
