  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 211, 'Joel 2:29', 'DAILY BREAD', 'joel', 'Joel', 2, ARRAY[29], 'Moreover, in those days I will pour out my spirit upon my servants and handmaids.') ON CONFLICT (date) DO NOTHING;
