  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 213, 'II Kings 3:26', 'DAILY BREAD', '2kings', 'II Kings', 3, ARRAY[26], 'And when the king of Moab had seen this, specifically, that the enemies had prevailed, he took with him seven hundred men who draw the sword, so that he might break through to the king of Idumea. But they were unable.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 214, 'Job 30:16', 'DAILY BREAD', 'job', 'Job', 30, ARRAY[16], 'But now my soul withers within myself, and the days of affliction take hold of me.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 215, 'John 15:2', 'DAILY BREAD', 'john', 'John', 15, ARRAY[2], 'Every branch in me that does not bear fruit, he will take away. And each one that does bear fruit, he will cleanse, so that it may bring forth more fruit.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 216, 'II Kings 15:13', 'DAILY BREAD', '2kings', 'II Kings', 15, ARRAY[13], 'Shallum, the son of Jabesh, reigned in the thirty-ninth year of Azariah, the king of Judah. And he reigned for one month, in Samaria.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 217, 'II Maccabees 4:42', 'DAILY BREAD', '2maccabees', 'II Maccabees', 4, ARRAY[42], 'And indeed, many were wounded, and some were struck down; however, all were put to flight. And, as for the sacrilegious man, they executed him beside the treasury.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 218, 'Sirach 33:7', 'DAILY BREAD', 'sirach', 'Sirach', 33, ARRAY[7], 'Why does day follow after day, and light follow after light, and year follow after year, in accord with the sun?') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 219, 'John 8:11', 'DAILY BREAD', 'john', 'John', 8, ARRAY[11], 'And she said, “No one, Lord.” Then Jesus said: “Neither will I condemn you. Go, and now do not choose to sin anymore.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 220, 'Baruch 5:2', 'DAILY BREAD', 'baruch', 'Baruch', 5, ARRAY[2], 'God will surround you with a double garment of justice, and he will set a crown on your head of everlasting honor.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 221, 'Judges 11:3', 'DAILY BREAD', 'judges', 'Judges', 11, ARRAY[3], 'And so, fleeing and avoiding them, he lived in the land of Tob. And men who were indigent and robbers joined with him, and they followed him as their leader.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 222, 'Judges 13:9', 'DAILY BREAD', 'judges', 'Judges', 13, ARRAY[9], 'And the Lord heeded the prayer of Manoah, and the Angel of the Lord appeared again to his wife, sitting in a field. But her husband Manoah was not with her. And when she had seen the Angel,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 223, 'Deuteronomy 26:18', 'DAILY BREAD', 'deuteronomy', 'Deuteronomy', 26, ARRAY[18], 'Today, the Lord has chosen you, so that you may be his particular people, just as he has spoken to you, and so that you may keep all his precepts,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 224, 'II Timothy 4:5', 'DAILY BREAD', '2timothy', 'II Timothy', 4, ARRAY[5], 'But as for you, truly, be vigilant, laboring in all things. Do the work of an Evangelist, fulfilling your ministry. Show self-restraint.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 225, 'Ecclesiastes 11:2', 'DAILY BREAD', 'ecclesiastes', 'Ecclesiastes', 11, ARRAY[2], 'Give a portion to seven, and indeed even to eight. For you do not know what evil may be upon the earth in the future.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 226, 'Acts 22:7', 'DAILY BREAD', 'acts', 'Acts', 22, ARRAY[7], 'And falling to the ground, I heard a voice saying to me, ‘Saul, Saul, why are you persecuting me?’') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 227, 'Wisdom 4:4', 'DAILY BREAD', 'wisdom', 'Wisdom', 4, ARRAY[4], 'And if they spring forth with branches for a time, yet, being set infirmly, they will be shaken by the wind, and, by the superabundance of the winds, they will be eradicated.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 228, 'Song of Solomon 6:5', 'DAILY BREAD', 'song', 'Song of Solomon', 6, ARRAY[5], 'Your teeth are like a flock of sheep, which have ascended from the washing, each one with its identical twin, and not one among them is barren.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 229, 'II John 1:9', 'DAILY BREAD', '2john', 'II John', 1, ARRAY[9], 'Everyone who withdraws and does not remain in the doctrine of Christ, does not have God. Whoever remains in the doctrine, such a one as this has both the Father and the Son.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 230, 'Jonah 3:8', 'DAILY BREAD', 'jonah', 'Jonah', 3, ARRAY[8], 'And let men and beasts be covered with sackcloth, and let them cry out to the Lord with strength, and may man be converted from his evil way, and from the iniquity that is in their hands.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 231, 'I Thessalonians 5:3', 'DAILY BREAD', '1thessalonians', 'I Thessalonians', 5, ARRAY[3], 'For when they will say, “Peace and security!” then destruction will suddenly overwhelm them, like the labor pains of a woman with child, and they will not escape.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 232, 'Daniel 10:15', 'DAILY BREAD', 'daniel', 'Daniel', 10, ARRAY[15], 'And while he was speaking words to me in this way, I cast my face down to the ground and was silent.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 233, 'I Kings 18:6', 'DAILY BREAD', '1kings', 'I Kings', 18, ARRAY[6], 'And they divided the regions among themselves, so that they might travel through them. Ahab went one way alone, and Obadiah went another way by himself.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 234, 'Joshua 21:25', 'DAILY BREAD', 'joshua', 'Joshua', 21, ARRAY[25], 'then, from the one half tribe of Manasseh, Taanach and Gath-Rimmon, with their suburbs, two cities.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 235, 'II Corinthians 13:7', 'DAILY BREAD', '2corinthians', 'II Corinthians', 13, ARRAY[7], 'Now we pray to God that you shall do nothing evil, not so that we may seem to be approved, but so that you may do what is good, even if we seem like reprobates.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 236, 'Obadiah 1:15', 'DAILY BREAD', 'obadiah', 'Obadiah', 1, ARRAY[15], 'For the day of the Lord is near, over all nations. Just as you have done, so will it be done to you. He will turn back your retribution on your own head.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 237, 'II Peter 1:3', 'DAILY BREAD', '2peter', 'II Peter', 1, ARRAY[3], 'in the same manner that all things which are for life and piety have been given to us by his Divine virtue, through the plan of him who has called us to our own glory and virtue.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 238, 'Genesis 17:15', 'DAILY BREAD', 'genesis', 'Genesis', 17, ARRAY[15], 'God said also to Abraham: “Your wife Sarai, you shall not call Sarai, but Sarah.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 239, 'Proverbs 17:7', 'DAILY BREAD', 'proverbs', 'Proverbs', 17, ARRAY[7], 'Well-chosen words are not fitting for the foolish, nor are lying lips fitting for a leader.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 240, 'Haggai 1:8', 'DAILY BREAD', 'haggai', 'Haggai', 1, ARRAY[8], 'Ascend to the mountain, bring wood and build the house, and it shall be acceptable to me, and I shall be glorified, says the Lord.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 241, 'Ephesians 3:15', 'DAILY BREAD', 'ephesians', 'Ephesians', 3, ARRAY[15], 'from whom all paternity in heaven and on earth takes its name.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 242, 'Jude 1:17', 'DAILY BREAD', 'jude', 'Jude', 1, ARRAY[17], 'But as for you, most beloved, be mindful of the words which have been foretold by the Apostles of our Lord Jesus Christ,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 243, 'I John 5:5', 'DAILY BREAD', '1john', 'I John', 5, ARRAY[5], 'Who is it that overcomes the world? Only he who believes that Jesus is the Son of God!') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 244, 'Ruth 1:14', 'DAILY BREAD', 'ruth', 'Ruth', 1, ARRAY[14], 'In response, they lifted up their voice and began to weep again. Orpah kissed her mother-in-law, and then turned back. Ruth clung to her mother-in-law.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 245, 'Colossians 1:19', 'DAILY BREAD', 'colossians', 'Colossians', 1, ARRAY[19], 'For the Father is well-pleased that all fullness reside in him,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 246, 'Hosea 14:2', 'DAILY BREAD', 'hosea', 'Hosea', 14, ARRAY[2], 'Israel, convert to the Lord your God. For you have been ruined by your own iniquity.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 247, 'Joel 1:9', 'DAILY BREAD', 'joel', 'Joel', 1, ARRAY[9], 'Sacrifice and libation have perished from the house of the Lord; the priests who are ministers of the Lord have mourned.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 248, 'II Kings 17:15', 'DAILY BREAD', '2kings', 'II Kings', 17, ARRAY[15], 'And they cast aside his ordinances, and the covenant that he formed with their fathers, and the testimonies which he testified to them. And they pursued vanities and acted vainly. And they followed the nations that were all around them, concerning the things which the Lord had commanded them not to do, and which they did.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 249, 'III John 1:2', 'DAILY BREAD', '3john', 'III John', 1, ARRAY[2], 'Most beloved, concerning everything, I make it my prayer that you may benefit by advancing and succeeding in whatever may be to the benefit of your soul.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 250, 'I Maccabees 6:60', 'DAILY BREAD', '1maccabees', 'I Maccabees', 6, ARRAY[60], 'And the idea was pleasing in the sight of the king and the leaders. And he sent to them to make peace. And they accepted it.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 251, 'Hosea 7:10', 'DAILY BREAD', 'hosea', 'Hosea', 7, ARRAY[10], 'And the pride of Israel will be brought low before his face, for they have not returned to the Lord their God, nor have they sought him in all of this.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 252, 'Esther 9:18', 'DAILY BREAD', 'esther', 'Esther', 9, ARRAY[18], 'But, as for those who were carrying out the killings in the city of Susa, they turned to killing on the thirteenth and fourteenth day of the same month. But on the fifteenth day they ceased to attack. And for that reason they established that day as sacred, with feasting and with gladness.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 253, 'II Kings 1:13', 'DAILY BREAD', '2kings', 'II Kings', 1, ARRAY[13], 'Again, he sent a third leader of fifty men and the fifty who were with him. And when he had arrived, he bent his knees before Elijah, and he pleaded with him, and said: “Man of God, do not choose to despise my life and the lives of your servants who are with me.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 254, 'Daniel 6:1', 'DAILY BREAD', 'daniel', 'Daniel', 6, ARRAY[1], 'It pleased Darius, and so he appointed over the kingdom one hundred twenty governors, to be placed throughout his whole kingdom.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 255, 'Malachi 2:8', 'DAILY BREAD', 'malachi', 'Malachi', 2, ARRAY[8], 'But you have withdrawn from the way, and you have scandalized very many in the law. You have nullified the covenant of Levi, says the Lord of hosts.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 256, 'Revelation of John 22:15', 'DAILY BREAD', 'revelation', 'Revelation of John', 22, ARRAY[15], 'Outside are dogs, and drug users, and homosexuals, and murderers, and those who serve idols, and all who love and do what is false.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 257, 'I Kings 13:19', 'DAILY BREAD', '1kings', 'I Kings', 13, ARRAY[19], 'And he led him back with him. Then he ate bread and drank water in his house.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 258, 'I John 2:25', 'DAILY BREAD', '1john', 'I John', 2, ARRAY[25], 'And this is the Promise, which he himself has promised to us: Eternal Life.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 259, 'Deuteronomy 30:10', 'DAILY BREAD', 'deuteronomy', 'Deuteronomy', 30, ARRAY[10], 'but only if you will listen to the voice of the Lord your God, and keep his precepts and ceremonies, which have been written in this law, and only if you return to the Lord your God with all your heart and with all your soul.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 260, 'Habakkuk 1:16', 'DAILY BREAD', 'habakkuk', 'Habakkuk', 1, ARRAY[16], 'For this reason, he will offer victims to his dragnet, and he will sacrifice to his netting. For through them, his portion has been made fat, and his meals elite.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 261, 'I Corinthians 9:8', 'DAILY BREAD', '1corinthians', 'I Corinthians', 9, ARRAY[8], 'Am I saying these things according to man? Or does the law not also say these things?') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 262, 'Ezekiel 34:18', 'DAILY BREAD', 'ezekiel', 'Ezekiel', 34, ARRAY[18], 'Was it not enough for you to feed upon good pastures? For you even trample with your feet upon the remainder of your pastures. And when you drank the purist water, you disturbed the remainder with your feet.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 263, 'II Timothy 4:2', 'DAILY BREAD', '2timothy', 'II Timothy', 4, ARRAY[2], 'that you should preach the word urgently, in season and out of season: reprove, entreat, rebuke, with all patience and doctrine.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 264, 'Ruth 2:10', 'DAILY BREAD', 'ruth', 'Ruth', 2, ARRAY[10], 'She, falling on her face and paying homage on the ground, said to him: “How did this happen to me, that I should find favor before your eyes, and that you would condescend to accept me, a foreign woman?”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 265, 'Haggai 1:8', 'DAILY BREAD', 'haggai', 'Haggai', 1, ARRAY[8], 'Ascend to the mountain, bring wood and build the house, and it shall be acceptable to me, and I shall be glorified, says the Lord.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 266, 'Song of Solomon 8:13', 'DAILY BREAD', 'song', 'Song of Solomon', 8, ARRAY[13], 'Groom: My vineyard is before me. The thousand is for your peacefulness, and two hundred is for those who care for its fruit.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 267, 'Zechariah 10:2', 'DAILY BREAD', 'zechariah', 'Zechariah', 10, ARRAY[2], 'For the images have been speaking what is useless, and the diviners have seen a lie, and the dreamers have been speaking false hope: they have comforted in vain. For this reason, they have been led away like a flock; they will be afflicted, because they have no shepherd.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 268, 'Zephaniah 1:8', 'DAILY BREAD', 'zephaniah', 'Zephaniah', 1, ARRAY[8], 'And this shall be: in the day of the victim of the Lord, I will visit upon the leaders, and upon the sons of the king, and upon all who have been clothed with strange garments.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 269, 'Jeremiah 26:14', 'DAILY BREAD', 'jeremiah', 'Jeremiah', 26, ARRAY[14], 'But as for me, behold, I am in your hands. Do to me what is good and right in your eyes.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 270, 'II Kings 4:20', 'DAILY BREAD', '2kings', 'II Kings', 4, ARRAY[20], 'But when he had taken him, and he had led him to his mother, she placed him upon her knees, until midday, and then he died.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 271, 'John 2:16', 'DAILY BREAD', 'john', 'John', 2, ARRAY[16], 'And to those who were selling doves, he said: “Take these things out of here, and do not make my Father’s house into a house of commerce.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 272, 'Ezekiel 47:13', 'DAILY BREAD', 'ezekiel', 'Ezekiel', 47, ARRAY[13], 'Thus says the Lord God: “This is the border, by which you shall possess the land, in accord with the twelve tribes of Israel. For Joseph shall have a double portion.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 273, 'II Maccabees 10:1', 'DAILY BREAD', '2maccabees', 'II Maccabees', 10, ARRAY[1], 'But Maccabeus and those who were with him, the Lord protecting them, even recovered the temple and the city.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 274, 'I Chronicles 12:6', 'DAILY BREAD', '1chronicles', 'I Chronicles', 12, ARRAY[6], 'Elkanah, and Isshiah, and Azarel, and Joezer, and Jashobeam, from Carehim;') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 275, 'John 5:8', 'DAILY BREAD', 'john', 'John', 5, ARRAY[8], 'Jesus said to him, “Rise, take up your stretcher, and walk.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 276, 'Baruch 2:27', 'DAILY BREAD', 'baruch', 'Baruch', 2, ARRAY[27], 'And you have accomplished in us, O Lord our God, according to all your goodness and according to all your great mercy,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 277, 'Isaiah 56:2', 'DAILY BREAD', 'isaiah', 'Isaiah', 56, ARRAY[2], 'Blessed is the man who does this, and the son of man who holds to this, keeping the Sabbath and not profaning it, guarding his hands and not doing any evil.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 278, 'Haggai 2:18', 'DAILY BREAD', 'haggai', 'Haggai', 2, ARRAY[18], 'how I struck you with a burning wind, and a mildew, and a hailstorm, all the works of your hand, yet there was no one among you who returned to me, says the Lord.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 279, 'II Kings 12:16', 'DAILY BREAD', '2kings', 'II Kings', 12, ARRAY[16], 'Yet truly, the money for offenses and the money for sins, they did not bring into the temple of the Lord, since it was for the priests.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 280, 'Ezra 10:25', 'DAILY BREAD', 'ezra', 'Ezra', 10, ARRAY[25], 'And out of Israel, from the sons of Parosh, Ramiah, and Izziah, and Malchijah, and Mijamin, and Eleazar, and Malchijah, and Benaiah.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 281, 'Nahum 2:12', 'DAILY BREAD', 'nahum', 'Nahum', 2, ARRAY[12], 'The lion seized enough for his young, and killed enough for his lionesses, and he filled his caves with prey, and his den with spoils.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 282, 'Hosea 11:5', 'DAILY BREAD', 'hosea', 'Hosea', 11, ARRAY[5], 'He will not return to the land of Egypt, but Assur himself will be the king over him, because they were not willing to be converted.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 283, 'Psalms 132:3', 'DAILY BREAD', 'psalms', 'Psalms', 132, ARRAY[3], 'It is like the dew of Hermon, which descended from mount Zion. For in that place, the Lord has commanded a blessing, and life, even unto eternity.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 284, 'Wisdom 3:5', 'DAILY BREAD', 'wisdom', 'Wisdom', 3, ARRAY[5], 'Troubled in few things, in many things they will be well compensated, because God has tested them and found them worthy of himself.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 285, 'Colossians 4:3', 'DAILY BREAD', 'colossians', 'Colossians', 4, ARRAY[3], 'Pray together, for us also, so that God may open a door of speech to us, so as to speak the mystery of Christ, (because of which, even now, I am in chains)') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 286, 'II Kings 8:25', 'DAILY BREAD', '2kings', 'II Kings', 8, ARRAY[25], 'In the twelfth year of Joram, the son of Ahab, the king of Israel: Ahaziah, the son of Jehoram, the king of Judah, reigned.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 287, 'Esther 6:12', 'DAILY BREAD', 'esther', 'Esther', 6, ARRAY[12], 'And Mordecai returned to the palace door. And Haman hurried to go to his house, mourning and hiding his head.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 288, 'III John 1:10', 'DAILY BREAD', '3john', 'III John', 1, ARRAY[10], 'Because of this, when I come, I will admonish his works which he does, babbling against us with malicious words. And as if this were not sufficient for him, he himself does not receive the brothers. And those who do receive them, he hinders, and he ejects them from the church.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 289, 'Zechariah 10:4', 'DAILY BREAD', 'zechariah', 'Zechariah', 10, ARRAY[4], 'From him will go forth the angle, from him the wooden peg, from him the bow of battle, from him every exactor at the same time.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 290, 'Jonah 4:10', 'DAILY BREAD', 'jonah', 'Jonah', 4, ARRAY[10], 'And the Lord said, “You grieve for the ivy, for which you have not labored and which you did not cause to grow, though it had been born during one night, and during one night perished.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 291, 'Nehemiah 13:7', 'DAILY BREAD', 'nehemiah', 'Nehemiah', 13, ARRAY[7], 'And I went to Jerusalem, and I understood the evil that Eliashib had done for Tobiah, such that he would make him a storeroom in the vestibules of the house of God.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 292, 'John 10:37', 'DAILY BREAD', 'john', 'John', 10, ARRAY[37], 'If I do not do the works of my Father, do not believe in me.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 293, 'Colossians 2:3', 'DAILY BREAD', 'colossians', 'Colossians', 2, ARRAY[3], 'For in him are hidden all treasures of wisdom and knowledge.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 294, 'Joel 3:20', 'DAILY BREAD', 'joel', 'Joel', 3, ARRAY[20], 'And Judea will be inhabited forever, and Jerusalem for generation upon generation.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 295, 'Haggai 2:21', 'DAILY BREAD', 'haggai', 'Haggai', 2, ARRAY[21], 'And the word of the Lord came a second time to Haggai, on the twenty-fourth of the month, saying:') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 296, 'Genesis 39:12', 'DAILY BREAD', 'genesis', 'Genesis', 39, ARRAY[12], 'And she, grasping the hem of his garment, said, “Sleep with me.” But he, leaving behind the cloak in her hand, fled and went outside.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 297, 'Titus 2:4', 'DAILY BREAD', 'titus', 'Titus', 2, ARRAY[4], 'so that they may teach prudence to the young women, so that they may love their husbands, love their children,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 298, 'Hebrews 1:5', 'DAILY BREAD', 'hebrews', 'Hebrews', 1, ARRAY[5], 'For to which of the Angels has he ever said: “You are my Son; today have I begotten you?” Or again: “I will be a Father to him, and he shall be a Son to me?”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 299, 'Jonah 3:4', 'DAILY BREAD', 'jonah', 'Jonah', 3, ARRAY[4], 'And Jonah began to enter into the city one day’s journey. And he cried out and said, “Forty days more and Nineveh shall be destroyed.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 300, 'Titus 1:16', 'DAILY BREAD', 'titus', 'Titus', 1, ARRAY[16], 'They claim that they know God. But, by their own works, they deny him, since they are abominable, and unbelieving, and reprobate, toward every good work.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 301, 'I Peter 3:12', 'DAILY BREAD', '1peter', 'I Peter', 3, ARRAY[12], 'For the eyes of the Lord are upon the just, and his ears are with their prayers, but the countenance of the Lord is upon those who do evil.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 302, 'II Peter 1:12', 'DAILY BREAD', '2peter', 'II Peter', 1, ARRAY[12], 'For this reason, I will always begin to admonish you about these things, even though, certainly, you know them and are confirmed in the present truth.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 303, 'James 3:6', 'DAILY BREAD', 'james', 'James', 3, ARRAY[6], 'And so the tongue is like a fire, comprising all iniquity. The tongue, stationed in the midst of our body, can defile the entire body and inflame the wheel of our nativity, setting a fire from Hell.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 304, 'Revelation of John 6:4', 'DAILY BREAD', 'revelation', 'Revelation of John', 6, ARRAY[4], 'And another horse went forth, which was red. And it was granted to him who was sitting upon it that he would take peace from the earth, and that they would kill one another. And a great sword was given to him.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 305, 'Sirach 40:18', 'DAILY BREAD', 'sirach', 'Sirach', 40, ARRAY[18], 'The life of a worker, when content with what is sufficient, will become sweet, and in it you will find a treasure.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 306, 'Joel 1:1', 'DAILY BREAD', 'joel', 'Joel', 1, ARRAY[1], 'The word of the Lord that came to Joel, the son of Pethuel.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 307, 'Hosea 6:4', 'DAILY BREAD', 'hosea', 'Hosea', 6, ARRAY[4], 'What am I to do with you, Ephraim? What am I to do with you, Judah? Your mercy is like the morning mist, and like the dew passing away in the morning.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 308, 'Psalms 23:6', 'DAILY BREAD', 'psalms', 'Psalms', 23, ARRAY[6], 'This is the generation that seeks him, that seeks the face of the God of Jacob.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 309, 'Psalms 140:2', 'DAILY BREAD', 'psalms', 'Psalms', 140, ARRAY[2], 'Let my prayer be guided like incense in your sight: the lifting up of my hands, like the evening sacrifice.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 310, 'Jeremiah 17:13', 'DAILY BREAD', 'jeremiah', 'Jeremiah', 17, ARRAY[13], 'O Lord, Hope of Israel: all who forsake you will be confounded. Those who withdraw from you will be written into the earth. For they have abandoned the Lord, the Source of living waters.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 311, 'II Samuel 17:25', 'DAILY BREAD', '2samuel', 'II Samuel', 17, ARRAY[25], 'Truly, Absalom appointed Amasa in place of Joab over the army. Now Amasa was the son of a man who was called Ithra of Jezrael, who entered to Abigail, the daughter of Nahash, the sister of Zeruiah, who was the mother of Joab.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 312, 'Obadiah 1:4', 'DAILY BREAD', 'obadiah', 'Obadiah', 1, ARRAY[4], 'Though you have been lifted high like an eagle, and though you have placed your nest among the stars, from there I will pull you down, says the Lord.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 313, 'II Corinthians 5:20', 'DAILY BREAD', '2corinthians', 'II Corinthians', 5, ARRAY[20], 'Therefore, we are ambassadors for Christ, so that God is exhorting through us. We beseech you for Christ: be reconciled to God.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 314, 'I Timothy 4:11', 'DAILY BREAD', '1timothy', 'I Timothy', 4, ARRAY[11], 'Instruct and teach these things.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 315, 'Isaiah 9:1', 'DAILY BREAD', 'isaiah', 'Isaiah', 9, ARRAY[1], 'In the earlier time, the land of Zebulun and the land of Naphtali were lifted up. But in the later time, the way of the sea beyond the Jordan, the Galilee of the Gentiles, was weighed down.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 316, 'Titus 2:6', 'DAILY BREAD', 'titus', 'Titus', 2, ARRAY[6], 'Exhort young men similarly, so that they may show self-restraint.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 317, 'Philippians 1:2', 'DAILY BREAD', 'philippians', 'Philippians', 1, ARRAY[2], 'Grace and peace to you, from God our Father and from the Lord Jesus Christ.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 318, 'Jude 1:21', 'DAILY BREAD', 'jude', 'Jude', 1, ARRAY[21], 'keeping yourselves in the love of God, and anticipating the mercy of our Lord Jesus Christ unto eternal life.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 319, 'Jonah 1:5', 'DAILY BREAD', 'jonah', 'Jonah', 1, ARRAY[5], 'And the mariners were afraid, and the men cried out to their god. And they threw the containers that were in the ship into the sea in order to lighten it of them. And Jonah went down into the interior of the ship, and he fell into a painful deep sleep.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 320, 'Jonah 2:2', 'DAILY BREAD', 'jonah', 'Jonah', 2, ARRAY[2], 'And Jonah prayed to the Lord, his God, from the belly of the fish.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 321, 'Ezekiel 6:12', 'DAILY BREAD', 'ezekiel', 'Ezekiel', 6, ARRAY[12], 'Whoever is far away will die of pestilence. But whoever is near will fall by the sword. And whoever remains and is besieged will die by famine. And I will fulfill my indignation among them.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 322, 'Malachi 3:17', 'DAILY BREAD', 'malachi', 'Malachi', 3, ARRAY[17], 'And they will be my special possession, says the Lord of hosts, on the day that I act. And I will spare them, just as a man spares his son who serves him.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 323, 'II Thessalonians 1:11', 'DAILY BREAD', '2thessalonians', 'II Thessalonians', 1, ARRAY[11], 'Because of this, too, we pray always for you, so that our God may make you worthy of his calling and may complete every act of his goodness, as well as his work of faith in virtue,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 324, 'Philemon 1:12', 'DAILY BREAD', 'philemon', 'Philemon', 1, ARRAY[12], 'So I have sent him back to you. And may you receive him like my own heart.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 325, 'Deuteronomy 27:14', 'DAILY BREAD', 'deuteronomy', 'Deuteronomy', 27, ARRAY[14], 'And the Levites shall pronounce and declare to all the men of Israel, with an exalted voice:') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 326, 'Tobit 7:20', 'DAILY BREAD', 'tobit', 'Tobit', 7, ARRAY[20], 'And she said to her, “Be steadfast in spirit, my daughter. May the Lord of heaven give you gladness in place of the grief that you have had to endure.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 327, 'Habakkuk 3:15', 'DAILY BREAD', 'habakkuk', 'Habakkuk', 3, ARRAY[15], 'You made a way in the sea for your horses, in the mud of great waters.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 328, 'I Corinthians 8:5', 'DAILY BREAD', '1corinthians', 'I Corinthians', 8, ARRAY[5], 'For although there are things that are called gods, whether in heaven or on earth, (if one even considers there to be many gods and many lords)') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 329, 'Mark 16:7', 'DAILY BREAD', 'mark', 'Mark', 16, ARRAY[7], 'But go, tell his disciples and Peter that he is going before you into Galilee. There you shall see him, just as he told you.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 330, 'James 1:3', 'DAILY BREAD', 'james', 'James', 1, ARRAY[3], 'knowing that the proving of your faith exercises patience,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 331, 'Psalms 62:9', 'DAILY BREAD', 'psalms', 'Psalms', 62, ARRAY[9], 'My soul has clung close to you. Your right hand has supported me.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 332, 'Daniel 6:26', 'DAILY BREAD', 'daniel', 'Daniel', 6, ARRAY[26], 'It is hereby established by my decree that, in all my empire and my kingdom, they shall begin to tremble and fear the God of Daniel. For he is the living and eternal God forever, and his kingdom will not be destroyed, and his power will last forever.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 333, 'Genesis 42:36', 'DAILY BREAD', 'genesis', 'Genesis', 42, ARRAY[36], 'Their father Jacob said, “You have caused me to be without children. Joseph is not living, Simeon is held in chains, and Benjamin you would carry away. All these evils have fallen back upon me.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 334, 'Joshua 12:9', 'DAILY BREAD', 'joshua', 'Joshua', 12, ARRAY[9], 'The king of Jericho, one; the king of Ai, which is beside Bethel, one;') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 335, 'Daniel 1:19', 'DAILY BREAD', 'daniel', 'Daniel', 1, ARRAY[19], 'And, when the king conversed with them, there had not been found any so great in all the world as Daniel, Hananiah, Mishael, and Azariah; and so they stood in the sight of the king.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 336, 'III John 1:3', 'DAILY BREAD', '3john', 'III John', 1, ARRAY[3], 'I was very glad when the brothers arrived, and when they offered testimony to the truth in you, that you are walking in the truth.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 337, 'III John 1:3', 'DAILY BREAD', '3john', 'III John', 1, ARRAY[3], 'I was very glad when the brothers arrived, and when they offered testimony to the truth in you, that you are walking in the truth.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 338, 'Obadiah 1:20', 'DAILY BREAD', 'obadiah', 'Obadiah', 1, ARRAY[20], 'And the exiles of this army of the sons of Israel, all the places of the Canaanites all the way to Sarepta, and the exiles of Jerusalem who are in Bosphoro, will possess the cities of the South.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 339, 'Wisdom 15:8', 'DAILY BREAD', 'wisdom', 'Wisdom', 15, ARRAY[8], 'And with effort he molds an empty god of the same clay, he who a little before had been made from the earth, and, after brief time, he himself returns from whence he came, to be claimed by he who holds the debt of his soul.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 340, 'Philippians 1:15', 'DAILY BREAD', 'philippians', 'Philippians', 1, ARRAY[15], 'Certainly, some do so even because of envy and contention; and others, too, do so because of a good will to preach Christ.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 341, 'I Kings 16:11', 'DAILY BREAD', '1kings', 'I Kings', 16, ARRAY[11], 'And when he had reigned and had sat upon his throne, he struck down the entire house of Baasha. And he did not leave behind of them anything that urinates against a wall, among both close relatives and his friends.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 342, 'Baruch 5:8', 'DAILY BREAD', 'baruch', 'Baruch', 5, ARRAY[8], 'Yet the woods and every sweet-smelling tree have provided shade for Israel by the commandment of God.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 343, 'I Chronicles 18:6', 'DAILY BREAD', '1chronicles', 'I Chronicles', 18, ARRAY[6], 'And he stationed soldiers in Damascus, so that Syria also would serve him, and would offer gifts. And the Lord assisted him in all the things to which he went forth.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 344, 'John 5:43', 'DAILY BREAD', 'john', 'John', 5, ARRAY[43], 'I have come in the name of my Father, and you do not accept me. If another will arrive in his own name, him you will accept.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 345, 'Micah 2:12', 'DAILY BREAD', 'micah', 'Micah', 2, ARRAY[12], 'I will gather together in a congregation all of you, Jacob. I will lead together as one, the remnant of Israel. I will set them together like a flock in the fold, like a sheep in the midst of the sheep pen. They will cause a tumult before the multitude of men.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 346, 'I Samuel 9:2', 'DAILY BREAD', '1samuel', 'I Samuel', 9, ARRAY[2], 'And he had a son called Saul, an elect and good man. And there was not a man among the sons of Israel better than he was. For he stood head and shoulders above all the people.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 347, 'Mark 5:13', 'DAILY BREAD', 'mark', 'Mark', 5, ARRAY[13], 'And Jesus promptly gave them permission. And the unclean spirits, departing, entered into the swine. And the herd of about two thousand rushed down with great force into the sea, and they were drowned in the sea.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 348, 'Song of Solomon 8:9', 'DAILY BREAD', 'song', 'Song of Solomon', 8, ARRAY[9], 'Chorus: Our sister is little and has no breasts. What shall we do for our sister on the day when she is called upon?') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 349, 'Tobit 4:17', 'DAILY BREAD', 'tobit', 'Tobit', 4, ARRAY[17], 'Eat your bread with the hungry and the needy, and cover the naked with your own garments.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 350, 'Micah 6:7', 'DAILY BREAD', 'micah', 'Micah', 6, ARRAY[7], 'Would the Lord be pleased with thousands of rams, or with many thousands of fat he-goats? How could I give up my firstborn because of my evil deed, the fruit of my womb because of the sin of my soul?') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 351, 'I Peter 2:7', 'DAILY BREAD', '1peter', 'I Peter', 2, ARRAY[7], 'Therefore, to you who believe, he is honor. But to those who do not believe, the stone which the builders have rejected, the same has been made into the head of the corner,') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 352, 'II Samuel 19:30', 'DAILY BREAD', '2samuel', 'II Samuel', 19, ARRAY[30], 'And Mephibosheth responded to the king, “But now let him take it all, since my lord the king has been returned peacefully into his own house.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 353, 'Mark 2:28', 'DAILY BREAD', 'mark', 'Mark', 2, ARRAY[28], 'And so, the Son of man is Lord, even of the Sabbath.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 354, 'Ezekiel 39:13', 'DAILY BREAD', 'ezekiel', 'Ezekiel', 39, ARRAY[13], 'Then all the people of the earth will bury them, and this shall be for them a renowned day, on which I have been glorified, says the Lord God.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 355, 'II Thessalonians 3:18', 'DAILY BREAD', '2thessalonians', 'II Thessalonians', 3, ARRAY[18], 'May the grace of our Lord Jesus Christ be with you all. Amen.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 356, 'Genesis 4:3', 'DAILY BREAD', 'genesis', 'Genesis', 4, ARRAY[3], 'Then it happened, after many days, that Cain offered gifts to the Lord, from the fruits of the earth.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 357, 'I Samuel 16:7', 'DAILY BREAD', '1samuel', 'I Samuel', 16, ARRAY[7], 'And the Lord said to Samuel: “You should not look with favor on his face, nor on the height of his stature. For I have rejected him. Neither do I judge by the appearance of a man. For man sees those things that are apparent, but the Lord beholds the heart.”') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 358, 'II Samuel 12:3', 'DAILY BREAD', '2samuel', 'II Samuel', 12, ARRAY[3], 'But the poor man had nothing at all, except one little sheep, which he had bought and nourished. And she had grown up before him, together with his children, eating from his bread, and drinking from his cup, and sleeping in his bosom. And she was like a daughter to him.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 359, 'Colossians 4:18', 'DAILY BREAD', 'colossians', 'Colossians', 4, ARRAY[18], 'The greeting of Paul by my own hand. Remember my chains. May grace be with you. Amen.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 360, 'Sirach 23:11', 'DAILY BREAD', 'sirach', 'Sirach', 23, ARRAY[11], 'Just as a servant, continually interrogated, will not be without a bruise, so everyone who swears oaths and takes God’s name will not be entirely free from sin.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 361, 'Ecclesiastes 10:9', 'DAILY BREAD', 'ecclesiastes', 'Ecclesiastes', 10, ARRAY[9], 'Whoever carries away stones will be harmed by them. And whoever cuts down trees will be wounded by them.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 362, 'II Thessalonians 2:8', 'DAILY BREAD', '2thessalonians', 'II Thessalonians', 2, ARRAY[8], 'And then that iniquitous one shall be revealed, the one whom the Lord Jesus shall bring to ruin with the spirit of his mouth, and shall destroy at the brightness of his return:') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 363, 'Zephaniah 3:9', 'DAILY BREAD', 'zephaniah', 'Zephaniah', 3, ARRAY[9], 'For then I will restore to the people a chosen lip, so that all may invoke the name of the Lord and may serve him with one shoulder.') ON CONFLICT (date) DO NOTHING;
  INSERT INTO daily_readings (id, date, title, badge, book_id, book_name, chapter_number, verse_numbers, reading_text) VALUES (gen_random_uuid(), v_date + 364, 'I Kings 4:13', 'DAILY BREAD', '1kings', 'I Kings', 4, ARRAY[13], 'Bengeber, in Ramoth Gilead, who had the town of Jair, the son of Manasseh, in Gilead; the same was first in the entire region of Argob, which is in Bashan, sixty great cities with walls that had bronze bars;') ON CONFLICT (date) DO NOTHING;
